using System;
using System.IO;
using System.IO.Compression;

namespace Scout;

internal static class GenerateOutput
{
    private static readonly Lazy<byte[]> ManBytes = new(() => Inflate(ManCompressedBase64));
    private static readonly Lazy<byte[]> CompleteBashBytes = new(() => Inflate(CompleteBashCompressedBase64));
    private static readonly Lazy<byte[]> CompleteZshBytes = new(() => Inflate(CompleteZshCompressedBase64));
    private static readonly Lazy<byte[]> CompleteFishBytes = new(() => Inflate(CompleteFishCompressedBase64));
    private static readonly Lazy<byte[]> CompletePowerShellBytes = new(() => Inflate(CompletePowerShellCompressedBase64));

    internal static ReadOnlySpan<byte> Get(CliGenerateMode mode)
    {
        switch (mode)
        {
            case CliGenerateMode.Man:
                return ManBytes.Value;

            case CliGenerateMode.CompleteBash:
                return CompleteBashBytes.Value;

            case CliGenerateMode.CompleteZsh:
                return CompleteZshBytes.Value;

            case CliGenerateMode.CompleteFish:
                return CompleteFishBytes.Value;

            case CliGenerateMode.CompletePowerShell:
                return CompletePowerShellBytes.Value;

            default:
                return [];
        }
    }

